// ─── HELPER FUNCTIONS ─────────────────────────────────────────────────────────

export function getCompetitorById(id: string): CompetitorData | undefined {
  return competitors.find((c) => c.id === id)
}

export function getCompetitorByCompareSlug(slug: string): CompetitorData | undefined {
  return competitors.find((c) => c.slug === slug)
}

export function getCompetitorByReviewSlug(slug: string): CompetitorData | undefined {
  return competitors.find((c) => c.id === slug)
}

export function getAllCompareSlugs(): string[] {
  return competitors.map((c) => c.slug)
}

export function getAllReviewSlugs(): string[] {
  return competitors.map((c) => c.id)
}